1	import { spawn, type ChildProcess } from "child_process";
2	import { chromium, type BrowserContext, type BrowserContextOptions } from "playwright";
3	import type { BrowserMode, ProxyConfig } from "../sessions/types";
4	
5	type LaunchOptions = BrowserContextOptions & { channel?: string; headless?: boolean };
6	
7	export function buildLaunchOptions(
8	  mode: BrowserMode,
9	  proxy?: ProxyConfig | null,
10	  viewport?: { width: number; height: number }
11	): LaunchOptions {
12	  const opts: LaunchOptions = {
13	    headless: true,
14	    viewport: viewport ?? { width: 1280, height: 800 },
15	  };
16	
17	  if (mode === "chromium-new-headless") {
18	    opts.channel = "chromium";
19	  }
20	
21	  if (proxy) {
22	    opts.proxy = {
23	      server: proxy.server,
24	      ...(proxy.username !== undefined ? { username: proxy.username } : {}),
25	      ...(proxy.password !== undefined ? { password: proxy.password } : {}),
26	      ...(proxy.bypass !== undefined ? { bypass: proxy.bypass } : {}),
27	    };
28	  }
29	
30	  return opts;
31	}
32	
33	const CDP_TIMEOUT_MS = 10_000;
34	
35	/**
36	 * Resolve env-driven spawn args for the headed CDP path.
37	 * - Ozone: explicit FEATHER_OZONE_PLATFORM wins ("default"/"none"/"" => omit the flag and let
38	 *   Chromium auto-pick, which is correct on X11/Xvfb). Unset => wayland only if WAYLAND_DISPLAY is
39	 *   present, else omit. This replaces the previous hardcoded `--ozone-platform=wayland`, which
40	 *   crashed on X11/headless/CI.
41	 * - Headless: FEATHER_SPAWN_HEADLESS truthy => `--headless=new` (lets a display-less runner attach
42	 *   over CDP). Prefer Xvfb in CI to keep the headed fingerprint faithful; this is the fallback.
43	 * - Sandbox: FEATHER_SPAWN_NO_SANDBOX truthy => `--no-sandbox` (CI/containers can't initialize
44	 *   Chromium's user-namespace sandbox — without it Chromium aborts before exposing CDP). OFF by
45	 *   default so production never carries it; it is not JS-observable, so it doesn't affect the
46	 *   webdriver/anti-detection surface a website sees.
47	 */
48	function envTruthy(name: string): boolean {
49	  const v = (process.env[name] ?? "").toLowerCase();
50	  return v === "1" || v === "true" || v === "yes";
51	}
52	
53	export function resolveSpawnExtraArgs(): string[] {
54	  const out: string[] = [];
55	  const explicit = process.env.FEATHER_OZONE_PLATFORM;
56	  if (explicit !== undefined) {
57	    const v = explicit.trim().toLowerCase();
58	    if (v && v !== "default" && v !== "none") out.push(`--ozone-platform=${explicit.trim()}`);
59	  } else if (process.env.WAYLAND_DISPLAY) {
60	    out.push("--ozone-platform=wayland");
61	  }
62	  if (envTruthy("FEATHER_SPAWN_HEADLESS")) out.push("--headless=new");
63	  if (envTruthy("FEATHER_SPAWN_NO_SANDBOX")) out.push("--no-sandbox");
64	  return out;
65	}
66	
67	export async function spawnAndConnect(opts: {
68	  profilePath: string;
69	  executablePath: string;
70	}): Promise<{ context: BrowserContext; childProcess: ChildProcess }> {
71	  const args = [
72	    "--remote-debugging-port=0",
73	    `--user-data-dir=${opts.profilePath}`,
74	    "--no-first-run",
75	    "--no-default-browser-check",
76	    ...resolveSpawnExtraArgs(),
77	    "--disable-blink-features=AutomationControlled",
78	  ];
79	
80	  const child = spawn(opts.executablePath, args, { stdio: ["ignore", "ignore", "pipe"] });
81	
82	  const wsEndpoint = await new Promise<string>((resolve, reject) => {
83	    const timer = setTimeout(() => {
84	      child.kill();
85	      reject(new Error(`Chromium did not expose CDP within ${CDP_TIMEOUT_MS}ms`));
86	    }, CDP_TIMEOUT_MS);
87	
88	    child.stderr!.on("data", (chunk: Buffer) => {
89	      const match = chunk.toString().match(/DevTools listening on (ws:\/\/[^\s]+)/);
90	      if (match) {
91	        clearTimeout(timer);
92	        resolve(match[1]);
93	      }
94	    });
95	
96	    child.on("error", (err: Error) => {
97	      clearTimeout(timer);
98	      reject(new Error(`Failed to spawn Chromium: ${err.message}`));
99	    });
100	
101	    child.on("exit", (code: number | null) => {
102	      clearTimeout(timer);
103	      reject(new Error(`Chromium exited unexpectedly with code ${code}`));
104	    });
105	  });
106	
107	  try {
108	    const browser = await chromium.connectOverCDP(wsEndpoint);
109	    const context = browser.contexts()[0];
110	    return { context, childProcess: child };
111	  } catch (err) {
112	    child.kill();
113	    throw err;
114	  }
115	}
